SELECT name, brand, software_version
FROM network_devices
WHERE software_version = (SELECT MAX(software_version) FROM network_devices);

SELECT AVG(value) AS average_value
FROM device_monitoring
WHERE metric_type = 'Memory Usage';

SELECT COUNT(DISTINCT device_id)
FROM security_compliance
WHERE compliance_standard = 'HIPAA' AND status = 'Passed';

SELECT COUNT(device_id) AS device_count
FROM network_devices
WHERE provider_id = (SELECT provider_id FROM providers WHERE provider_name = 'DataIX Internet Exchange');

SELECT fault_category, root_cause, description
FROM fault_reports
WHERE fault_id = 0;

SELECT MIN(value) AS minimum_memory_usage
FROM device_monitoring
WHERE metric_type = 'Memory usage';

SELECT device_id AS device_identifier
FROM network_devices
ORDER BY device_id;

SELECT check_type, risk_level
FROM security_compliance
WHERE status = 'Failed';

SELECT device_id, COUNT(compliance_id) AS compliance_count
FROM security_compliance
GROUP BY device_id;

SELECT metric_type, value, timestamp
FROM device_monitoring
WHERE metric_type = 'Memory usage' AND value > 85.0;
